import { useCheckedTransactions } from './useCheckedTransactions';
import TransactionFormSidebar from './sidebars/TransactionFormSidebar';
import TransactionInfoSidebar from './sidebars/TransactionInfoSidebar';
import TransactionBulkSidebar from './sidebars/TransactionBulkSidebar';
import TransactionEditFormSidebar from './sidebars/TransactionEditFormSidebar';
import TransactionDeleteSidebar from './sidebars/TransactionDeleteSidebar';
import AddCategoriesSidebar from './sidebars/AddCategoriesSidebar';

const TransactionsPage = () => {
  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState<TransactionFiltersT>({
    bankAccountIds: [],
    categoryIds: [],
  });

  const [sortDirection, setSortDirection] = useState<SortOrderE>(
    SortOrderE.DESC,
  );

  const {
    loading,
    transactions,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
  } = useTransactionList(search, filters, sortDirection);

  const { checkedIds, onToggleCheckedItem } = useCheckedTransactions();

  const { bankAccounts, loading: bankLoading } = useLoadUserBankAccountList();
  const { userCategories, loading: categoryLoading } =
    useLoadUserCategoryList();

  const filtersLoading = bankLoading || categoryLoading;

  const handleClickTransaction = useCallback(
    (transactionId: UuidT) => {
      if (checkedIds.length > 0) {
        onToggleCheckedItem(transactionId);

        return;
      }

      sidebarService.closeAll();

      sidebarService.open(SidebarNameE.TRANSACTION_INFO, {
        transactionId,
      });
    },
    [checkedIds.length, onToggleCheckedItem],
  );

  const handleToggleSortDirection = useCallback(() => {
    setSortDirection(prev =>
      prev === SortOrderE.DESC ? SortOrderE.ASC : SortOrderE.DESC,
    );
  }, []);

  return (
    <SidebarLayout className="transactions-page">
      <PageHeader title="My transactions">
        <AuButton
          kind={AuButtonKindE.LINK}
          onClick={() => {
            sidebarService.open(SidebarNameE.TRANSACTION);
          }}
        >
          <PlusSvg />
          Add transaction
        </AuButton>
      </PageHeader>

      <div className="transactions-page__filter">
        <TransactionFilter
          onChang={setSearch}
          onFilterChange={setFilters}
          bankAccounts={bankAccounts}
          userCategories={userCategories ?? []}
          loadingFilters={filtersLoading}
        />
      </div>

      <div className="transactions-page__main">
        {loading && !transactions.length && (
          <div className="transactions-page__loading">
            <Spinner />
          </div>
        )}

        {!!transactions.length && (
          <>
            <TransactionList
              transactions={transactions}
              transactionsCheckedIds={checkedIds}
              onToggleTransactionCheck={onToggleCheckedItem}
              onTransactionClick={handleClickTransaction}
              onEndReached={() => {
                if (hasNextPage && !isFetchingNextPage) {
                  fetchNextPage();
                }
              }}
              sortDirection={sortDirection}
              onToggleSortDirection={handleToggleSortDirection}
            />

            {isFetchingNextPage && (
              <div className="transactions-page__loading-more">
                <Spinner />
              </div>
            )}
          </>
        )}

        {!loading && !transactions.length && (
          <EmptyState
            title="No transactions found"
            message="Try adjusting your filters or add a new transaction."
            action={
              <AuButton
                kind={AuButtonKindE.LINK}
                onClick={() => {
                  sidebarService.open(SidebarNameE.TRANSACTION);
                }}
              >
                <PlusSvg />
                Add transaction
              </AuButton>
            }
          />
        )}
      </div>

      <TransactionFormSidebar />

      <TransactionEditFormSidebar />

      <TransactionInfoSidebar />

      <TransactionBulkSidebar />

      <AddCategoriesSidebar />

      <TransactionDeleteSidebar />
    </SidebarLayout>
  );
};

export default TransactionsPage;

