import { globalStore } from 'Shared/store/globalStore';
import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { SidebarNameE } from 'Components/sidebar/types/SidebarNameE';

import { sidebarService } from './sidebarService';

describe('sidebarService', () => {
  const SIDEBAR_A = 'SIDEBAR_A' as SidebarNameE;
  const SIDEBAR_B = 'SIDEBAR_B' as SidebarNameE;

  beforeEach(() => {
    globalStore[GlobalStoreFieldE.SIDEBAR].value = [];
  });

  it('open prepends new sidebar to store and returns its name', () => {
    sidebarService.open(SIDEBAR_A);

    const sidebars = globalStore[GlobalStoreFieldE.SIDEBAR].value;

    expect(sidebars.length).toBe(1);
    expect(sidebars[0].name).toBe(SIDEBAR_A);
    expect(sidebars[0].deleted).toBe(false);
    expect(sidebars[0].props).toBeUndefined();
  });

  it('open keeps newest sidebar first and preserves previous ones', () => {
    sidebarService.open(SIDEBAR_A, { foo: 'bar' } as never);
    sidebarService.open(SIDEBAR_B);

    const sidebars = globalStore[GlobalStoreFieldE.SIDEBAR].value;

    expect(sidebars.length).toBe(2);
    expect(sidebars[0].name).toBe(SIDEBAR_B);
    expect(sidebars[1].name).toBe(SIDEBAR_A);
  });

  it('openFirst replaces all sidebars with the new one', () => {
    sidebarService.open(SIDEBAR_A);
    sidebarService.open(SIDEBAR_B);

    sidebarService.openFirst(SIDEBAR_A, { foo: 'baz' } as never);

    const sidebars = globalStore[GlobalStoreFieldE.SIDEBAR].value;

    expect(sidebars.length).toBe(1);
    expect(sidebars[0].name).toBe(SIDEBAR_A);
    expect(sidebars[0].props).toEqual({ foo: 'baz' });
  });

  it('close marks all sidebars with given name as deleted', () => {
    sidebarService.open(SIDEBAR_A);
    sidebarService.open(SIDEBAR_B);

    sidebarService.close(SIDEBAR_A);

    const sidebars = globalStore[GlobalStoreFieldE.SIDEBAR].value;

    expect(sidebars.length).toBe(2);
    expect(sidebars.find(s => s.name === SIDEBAR_A)?.deleted).toBe(true);
    expect(sidebars.find(s => s.name === SIDEBAR_B)?.deleted).toBe(false);
  });

  it('closeAll marks all sidebars as deleted', () => {
    sidebarService.open(SIDEBAR_A);
    sidebarService.open(SIDEBAR_B);

    sidebarService.closeAll();

    const sidebars = globalStore[GlobalStoreFieldE.SIDEBAR].value;

    expect(sidebars.length).toBe(2);
    expect(sidebars.every(s => s.deleted)).toBe(true);
  });

  it('finalizeClose removes all sidebars with given name', () => {
    sidebarService.open(SIDEBAR_A);
    sidebarService.open(SIDEBAR_B);
    sidebarService.open(SIDEBAR_A);

    sidebarService.finalizeClose(SIDEBAR_A);

    const sidebars = globalStore[GlobalStoreFieldE.SIDEBAR].value;

    expect(sidebars.length).toBe(1);
    expect(sidebars[0].name).toBe(SIDEBAR_B);
  });
});

