     2→import { describe, it, expect, vi, afterEach } from 'vitest';
     3→import { useSwipeGesture } from './useSwipeGesture';
     4→
     5→describe('useSwipeGesture', () => {
     6→  const createMockCallback = () => vi.fn() as unknown as () => void;
     7→
     8→  afterEach(() => {
     9→    vi.clearAllMocks();
    10→  });
    11→
    12→  it('should return a ref object', () => {
    13→    const { result } = renderHook(() =>
    14→      useSwipeGesture({
    15→        onSwipeDown: createMockCallback(),
    16→      }),
    17→    );
    18→
    19→    expect(result.current.ref).toBeDefined();
    20→    expect(result.current.ref.current).toBeNull();
    21→  });
    22→
    23→  it('should accept threshold option', () => {
    24→    const { result } = renderHook(() =>
    25→      useSwipeGesture({
    26→        onSwipeDown: createMockCallback(),
    27→        threshold: 150,
    28→      }),
    29→    );
    30→
    31→    expect(result.current.ref).toBeDefined();
    32→  });
    33→
    34→  it('should accept enabled option set to false', () => {
    35→    const { result } = renderHook(() =>
    36→      useSwipeGesture({
    37→        onSwipeDown: createMockCallback(),
    38→        enabled: false,
    39→      }),
    40→    );
    41→
    42→    expect(result.current.ref).toBeDefined();
    43→  });
    44→
    45→  it('should accept enabled option set to true', () => {
    46→    const { result } = renderHook(() =>
    47→      useSwipeGesture({
    48→        onSwipeDown: createMockCallback(),
    49→        enabled: true,
    50→      }),
    51→    );
    52→
    53→    expect(result.current.ref).toBeDefined();
    54→  });
    55→
    56→  it('should use default threshold when not provided', () => {
    57→    const { result } = renderHook(() =>
    58→      useSwipeGesture({
    59→        onSwipeDown: createMockCallback(),
    60→      }),
    61→    );
    62→
    63→    expect(result.current.ref).toBeDefined();
    64→  });
    65→
    66→  it('should use enabled=true by default', () => {
    67→    const { result } = renderHook(() =>
    68→      useSwipeGesture({
    69→        onSwipeDown: createMockCallback(),
    70→      }),
    71→    );
    72→
    73→    expect(result.current.ref).toBeDefined();
    74→  });
    75→
    76→  it('should accept onSwipeDown callback', () => {
    77→    const { result } = renderHook(() =>
    78→      useSwipeGesture({
    79→        onSwipeDown: createMockCallback(),
    80→      }),
    81→    );
    82→
    83→    expect(result.current.ref).toBeDefined();
    84→  });
    85→
    86→  it('should handle ref changes gracefully', () => {
    87→    const { result } = renderHook(() =>
    88→      useSwipeGesture({
    89→        onSwipeDown: createMockCallback(),
    90→        enabled: true,
    91→      }),
    92→    );
    93→
    94→    const mockElement1 = document.createElement('div');
    95→    const mockElement2 = document.createElement('div');
    96→
    97→    result.current.ref.current = mockElement1;
    98→    result.current.ref.current = mockElement2;
    99→    result.current.ref.current = null;
   100→
   101→    expect(result.current.ref.current).toBeNull();
   102→  });
   103→
   104→  it('should update when threshold prop changes', () => {
   105→    const callback = createMockCallback();
