import { test, expect } from '@playwright/test';

const EMAIL = 'zephyr.dev@zuratech.ca';
const CODE = '112233';

test('user can login and see budgets page', async ({ page }) => {
  await page.goto('/');

  await page.getByTestId('login-email-input').fill(EMAIL);

  const submitBtn = page.getByTestId('login-buton');
  await expect(submitBtn).toBeEnabled();
  await submitBtn.click();

  await page.getByTestId('auth-code-input').fill(CODE);
  await page.getByTestId('auth-buton').click();

  await expect(page).toHaveURL(/\/budgets/);
  await expect(page.getByTestId('user-link')).toBeVisible();
});

