import React from 'react';

type PropsT = {
  className?: string;
  children: React.ReactNode;
  fill?: 'none' | 'currentColor' | 'inherit' | 'transparent';
  height: number;
  stroke?: string;
  strokeWidth?: number;
  viewBoxHeight?: number;
  viewBoxWidth?: number;
  width: number;
  strokeLinecap?: 'round' | 'butt' | 'square' | 'inherit' | undefined;
  strokeLinejoin?: 'round' | 'inherit' | 'miter' | 'bevel' | undefined;
};

const Svg = ({
  className,
  children,
  height,
  fill = 'currentColor',
  stroke = 'currentColor',
  strokeWidth,
  width,
  viewBoxHeight = height,
  viewBoxWidth = width,
  strokeLinecap,
  strokeLinejoin,
}: PropsT) => (
  <svg
    aria-hidden="true"
    className={className}
    height={height}
    viewBox={`0 0 ${viewBoxWidth} ${viewBoxHeight}`}
    width={width}
    stroke={stroke}
    strokeWidth={strokeWidth}
    xmlns="http://www.w3.org/2000/svg"
    fill={fill}
    strokeLinecap={strokeLinecap}
    strokeLinejoin={strokeLinejoin}
  >
    {children}
  </svg>
);

export default Svg;

